import * as fs from 'fs';
import * as os from 'os';

describe('Dirty close with pending writes', () => {
  it('should emit drain before write_close when close is called with pending queue', async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'test.db');

    try {
      await new Promise<void>((resolve, reject) => {
        const timeout = setTimeout(() => {
          reject(new Error('Test timed out'));
        }, 5000);

        const Dirty = require('../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js');
        const db = new Dirty(dbPath);

        db.on('load', () => {
          // Block flushing so queue accumulates
          (db as any)._waitForDrain = true;

          for (let i = 0; i < 5; i++) {
            db.set(`key${i}`, { value: i });
          }

          // queue has 5 items, none written
          // Original: close() returns early, waits for drain
          // Mutant: close() calls _writeStream.end() immediately, losing queued data
          db.close();

          // Unblock and flush manually to trigger drain in original
          (db as any)._waitForDrain = false;
          if ((db as any)._writeStream) {
            (db as any)._flush();
          }

          db.on('write_close', () => {
            clearTimeout(timeout);
            // Read raw file to see how many records were written
            const content = fs.readFileSync(dbPath, 'utf-8');
            const lines = content.trim().split('\n').filter(Boolean);
            try {
              // Original: all 5 records written before close
              // Mutant: 0 records written (stream ended before flush)
              expect(lines.length).toBe(5);
              resolve();
            } catch (err) {
              reject(err);
            }
          });
        });

        db.on('error', (err: Error) => {
          clearTimeout(timeout);
          reject(err);
        });
      });
    } finally {
